#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
const int N = 705;
int n, m, ans;
int a[N][N];
bool vis[N][N];
int dx[] = {-1, -1, -1, 0, 0, 0, 1, 1, 1};
int dy[] = {-1, 0, 1, -1, 0, 1, -1, 0, 1};
struct node
{
	int x, y;
};
vector<node>v;
bool cmp(node s, node t)
{
	return a[s.x][s.y] > a[t.x][t.y];
}
void dfs(int x, int y)
{
	vis[x][y] = 1;
	for (int i = 0; i < 9; i++)
	{
		int nx = x + dx[i];
		int ny = y + dy[i];
		if (nx > n || nx < 1 || ny > m || ny < 1)continue;
		if (!vis[nx][ny] && a[nx][ny] <= a[x][y])
		{
			dfs(x + dx[i], y + dy[i]);
		}
	}
}
signed main(void)
{
	// freopen("P2919_3.in","r",stdin);
	// freopen("P2919.out","w",stdout);
	cin >> n >> m;
	for (int i = 1; i <= n; i++)
	{
		for (int j = 1; j <= m; j++)
		{
			cin >> a[i][j];
			v.push_back({i, j});
		}
	}
	sort(v.begin(), v.end(), cmp);
	for (auto &i : v)
	{
		if (!vis[i.x][i.y])
		{
			bool f = 1;
			for (int j = 0; j < 9; j++)
			{
				int nx = i.x + dx[j];
				int ny = i.y + dy[j];
				if (a[nx][ny] > a[i.x][i.y])
				{
					f = 0;
				}
			}
			if (f)
			{
				dfs(i.x, i.y);
				ans++;
			}
		}
	}
	cout << ans;
	return false;
}
